  await page.waitForTimeout(3000);
  const pos2 = await page.evaluate(() => window.__latestGameState.player_position);

  // Look for NPCs
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const allNpcs = s.nearby_entities.filter(e=>e.type===1).slice(0,10).map(e=>({name:e.name,x:e.x,y:e.y,dist:e.distance,id:e.id}));
    return {pos: s.player_position, hp: s.player_stats.hp, npcs: allNpcs, nearby: s.nearby_entities.slice(0,8).map(e=>({name:e.name,type:e.type,x:e.x,y:e.y,dist:e.distance,id:e.id}))};
